  83→const metricsState = {
  84→    startedAt: new Date().toISOString(),
  85→    requests: 0,
  86→    responses: 0,
  87→    inFlight: 0,
  88→    bytesSent: 0,
  89→    statusBuckets: {
  90→        '2xx': 0,
  91→        '3xx': 0,
  92→        '4xx': 0,
  93→        '5xx': 0,
