  99→const normalizeApiPath = (path = '') => (
 100→    String(path).startsWith('/api/')
 101→        ? String(path).slice(4)
 102→        : String(path)
 103→);
 104→
 105→const canonicalizeMetricsPath = (rawPath = '') => {
 106→    const normalized = normalizeApiPath(rawPath);
 107→    return normalized
 108→        .replace(/\/[0-9a-f]{8}-[0-9a-f-]{27,}(?=\/|$)/ig, '/:id')
 109→        .replace(/\/\d+(?=\/|$)/g, '/:id');
 110→};
