 112→const isPersonalizedGetRequest = (req) => {
 113→    if (req?.headers?.authorization) {
 114→        return true;
 115→    }
 116→
 117→    const userId = String(req?.query?.userId || '').trim();
 118→    const loggedInUserId = String(req?.query?.loggedInUserId || '').trim();
 119→    return Boolean(userId || loggedInUserId);
 120→};
 121→
 122→const isCacheablePublicPath = (reqPath = '') => (
 123→    CACHEABLE_PUBLIC_ROUTE_PATTERNS.some((pattern) => pattern.test(reqPath))
 124→);
