 134→const normalizeWhitespace = (value) => String(value ?? '')
 135→    .replace(/\s+/g, ' ')
 136→    .trim();
 137→
 138→const toPreviewText = (value, maxLength = SOCIAL_PREVIEW_MAX_CHARS) => {
 139→    const normalized = normalizeWhitespace(value);
 140→    if (!normalized) return '';
 141→    if (normalized.length <= maxLength) return normalized;
 142→    if (maxLength <= 3) return normalized.slice(0, maxLength);
 143→    return `${normalized.slice(0, maxLength - 3).trimEnd()}...`;
 144→};
