 154→const getRequestOrigin = (req) => {
 155→    const forwardedProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim().toLowerCase();
 156→    const forwardedHost = String(req.headers['x-forwarded-host'] || '').split(',')[0].trim();
 157→    const host = forwardedHost || req.get('host') || '';
 158→    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 159→    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 160→        ? forwardedProto
 161→        : requestProtocol === 'http' || requestProtocol === 'https'
 162→            ? requestProtocol
 163→            : 'https';
 164→
 165→    if (!host) {
 166→        return SITE_URL;
 167→    }
 168→
 169→    return `${protocol}://${host}`;
 170→};
