 172→const pickFirstNonEmptyString = (...values) => {
 173→    for (const value of values) {
 174→        if (typeof value === 'string') {
 175→            const trimmed = value.trim();
 176→            if (trimmed) return trimmed;
 177→        }
 178→    }
 179→    return '';
 180→};
