 182→const parseImageDimension = (value) => {
 183→    const parsed = Number(value);
 184→    if (!Number.isFinite(parsed)) return undefined;
 185→    return parsed;
 186→};
 187→
 188→const imageFromNodeLike = (nodeLike) => {
 189→    if (!nodeLike || typeof nodeLike !== 'object') return null;
 190→
 191→    const src = pickFirstNonEmptyString(
 192→        nodeLike.src,
 193→        nodeLike.url,
 194→        nodeLike.image_url,
 195→        nodeLike.imageUrl,
 196→        nodeLike?.payload?.src,
 197→        nodeLike?.data?.src
 198→    );
 199→    if (!src) return null;
 200→
 201→    return {
 202→        src,
 203→        width: parseImageDimension(nodeLike.width),
 204→        height: parseImageDimension(nodeLike.height),
 205→    };
 206→};
