 208→const extractFromLexical = (contentJson) => {
 209→    try {
 210→        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
 211→        const texts = [];
 212→        let firstImage = null;
 213→
 214→        const walk = (node) => {
 215→            if (!node || typeof node !== 'object') return;
 216→
 217→            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
 218→            if (nodeType === 'text' && typeof node.text === 'string') {
 219→                texts.push(node.text);
 220→            }
 221→
 222→            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
 223→            if (!firstImage && isImageNode) {
 224→                const image = imageFromNodeLike(node);
 225→                if (image) {
 226→                    firstImage = image;
 227→                }
 228→            }
 229→
 230→            if (Array.isArray(node.children)) {
 231→                node.children.forEach(walk);
 232→            }
 233→        };
 234→
 235→        if (parsed?.root) {
 236→            walk(parsed.root);
 237→        }
 238→
 239→        return {
 240→            text: normalizeWhitespace(texts.join(' ')),
 241→            image: firstImage
 242→        };
 243→    } catch {
 244→        return { text: '', image: null };
 245→    }
 246→};
 247→
 248→const extractFromCanvasDoc = (canvasDocRaw) => {
 249→    try {
 250→        const doc = typeof canvasDocRaw === 'string' ? JSON.parse(canvasDocRaw) : canvasDocRaw;
 251→        const text = Array.isArray(doc?.snippets)
 252→            ? normalizeWhitespace(
 253→                doc.snippets
 254→                    .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text : ''))
 255→                    .join(' ')
 256→            )
 257→            : '';
 258→
 259→        let image = null;
 260→        if (Array.isArray(doc?.images)) {
 261→            const first = doc.images.find((img) => imageFromNodeLike(img));
 262→            if (first) image = imageFromNodeLike(first);
 263→        }
 264→
 265→        return { text, image };
 266→    } catch {
 267→        return { text: '', image: null };
 268→    }
 269→};
