 271→const buildShareMetaFromJournal = (journal) => {
 272→    const lexicalData = extractFromLexical(journal?.content);
 273→    const canvasData = extractFromCanvasDoc(journal?.canvas_doc);
 274→    const normalizedTitle = typeof journal?.title === 'string' ? normalizeWhitespace(journal.title) : '';
 275→    const title = normalizedTitle || 'Untitled Post';
 276→    const authorName = normalizeWhitespace(journal?.users?.name) || 'Someone';
 277→
 278→    let description = lexicalData.text || '';
 279→    if (!description && canvasData.text) {
 280→        description = canvasData.text;
 281→    }
 282→    if (!description) {
 283→        description = `Read "${title}" by ${authorName} on Iskryb`;
 284→    }
 285→
 286→    let imageCandidate = DEFAULT_OG_IMAGE_URL;
 287→    let imageCandidateSource = 'fallback';
 288→    if (lexicalData.image?.src) {
 289→        imageCandidate = lexicalData.image.src;
 290→        imageCandidateSource = 'lexical';
 291→    } else if (canvasData.image?.src) {
 292→        imageCandidate = canvasData.image.src;
 293→        imageCandidateSource = 'canvas';
 294→    } else if (journal?.users?.image_url) {
 295→        imageCandidate = journal.users.image_url;
 296→        imageCandidateSource = 'author_avatar';
 297→    }
 298→
 299→    return {
 300→        title,
 301→        normalizedTitle,
 302→        description: toPreviewText(description),
 303→        imageCandidate,
 304→        imageCandidateSource
 305→    };
