 488→const convertToOgJpeg = async (inputBuffer) => {
 489→    return sharp(inputBuffer, { limitInputPixels: 60_000_000 })
 490→        .rotate()
 491→        .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, {
 492→            fit: 'contain',
 493→            background: { r: 255, g: 255, b: 255, alpha: 1 },
 494→        })
 495→        .jpeg({ quality: 82, mozjpeg: true })
 496→        .toBuffer();
 497→};
