 530→app.use(cors(corsOptions));
 531→app.use(compression({ threshold: 1024 }));
 532→app.disable("x-powered-by");
 533→app.use(
 534→    helmet({
 535→        contentSecurityPolicy: false,
 536→        crossOriginEmbedderPolicy: false,
 537→    })
 538→);
 539→
 540→app.use((req, res, next) => {
 541→    metricsState.requests += 1;
 542→    metricsState.inFlight += 1;
 543→
 544→    const startNs = process.hrtime.bigint();
 545→    let byteCount = 0;
 546→
 547→    const originalWrite = res.write.bind(res);
 548→    const originalEnd = res.end.bind(res);
 549→
 550→    res.write = (chunk, encoding, callback) => {
 551→        if (chunk) {
 552→            byteCount += Buffer.isBuffer(chunk)
 553→                ? chunk.length
 554→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 555→        }
 556→        return originalWrite(chunk, encoding, callback);
 557→    };
 558→
 559→    res.end = (chunk, encoding, callback) => {
 560→        if (chunk) {
 561→            byteCount += Buffer.isBuffer(chunk)
 562→                ? chunk.length
 563→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 564→        }
 565→        return originalEnd(chunk, encoding, callback);
 566→    };
 567→
 568→    res.on('finish', () => {
 569→        metricsState.inFlight = Math.max(0, metricsState.inFlight - 1);
 570→        metricsState.responses += 1;
 571→        metricsState.bytesSent += byteCount;
 572→
 573→        const statusBucket = classifyStatusBucket(res.statusCode);
 574→        metricsState.statusBuckets[statusBucket] += 1;
 575→
 576→        const durationMs = Number(process.hrtime.bigint() - startNs) / 1_000_000;
 577→        const routeTemplate = req.route?.path
 578→            ? `${req.baseUrl || ''}${req.route.path}`
 579→            : req.path;
 580→        const routeKey = `${req.method} ${canonicalizeMetricsPath(routeTemplate)}`;
 581→
 582→        let routeStat = metricsState.routeStats.get(routeKey);
 583→        if (!routeStat) {
 584→            if (metricsState.routeStats.size >= METRICS_ROUTE_LIMIT) {
 585→                return;
 586→            }
 587→
 588→            routeStat = {
 589→                count: 0,
 590→                totalDurationMs: 0,
 591→                maxDurationMs: 0,
 592→                bytesSent: 0,
 593→                statusBuckets: { '2xx': 0, '3xx': 0, '4xx': 0, '5xx': 0, other: 0 },
 594→            };
 595→            metricsState.routeStats.set(routeKey, routeStat);
 596→        }
 597→
 598→        routeStat.count += 1;
 599→        routeStat.totalDurationMs += durationMs;
 600→        routeStat.maxDurationMs = Math.max(routeStat.maxDurationMs, durationMs);
 601→        routeStat.bytesSent += byteCount;
 602→        routeStat.statusBuckets[statusBucket] += 1;
 603→    });
 604→
 605→    next();
 606→});
 607→
 608→app.use((req, res, next) => {
 609→    if (req.method !== "GET") {
 610→        return next();
 611→    }
 612→
 613→    const normalizedPath = normalizeApiPath(req.path);
 614→    const isPersonalized = isPersonalizedGetRequest(req);
 615→
 616→    if (!isPersonalized && isCacheablePublicPath(normalizedPath)) {
 617→        res.set("Cache-Control", PUBLIC_CACHE_CONTROL_VALUE);
 618→    } else if (isPersonalized) {
 619→        res.set("Cache-Control", PRIVATE_NO_STORE_CACHE_CONTROL);
 620→    }
 621→
 622→    return next();
 623→});
 624→
 625→app.use(express.json({ limit: "2mb" }));
 626→app.use(express.urlencoded({extended: true, limit: "2mb", parameterLimit: 1000}));
