 809→app.get('/share/post/:journalId/image', async (req, res) => {
 810→    const { journalId } = req.params;
 811→    await ensureShareFonts();
 812→    const debugMode = isShareImageDebugRequest(req);
 813→    const debugPayload = {
 814→        ok: false,
 815→        fallback: false,
 816→        journalId,
 817→        stage: 'start',
 818→        reason: '',
 819→        meta: {
 820→            imageCandidateSource: null,
 821→            imageCandidateRaw: null,
 822→            imageCandidateResolved: null,
 823→            upstreamFinalUrl: null,
 824→            upstreamContentType: null,
 825→            upstreamBytes: null,
 826→            outputBytes: null,
 827→        },
 828→    };
 829→
 830→    const fallbackWithReason = (reason) => {
 831→        debugPayload.ok = false;
 832→        debugPayload.fallback = true;
 833→        debugPayload.stage = 'fallback';
 834→        debugPayload.reason = reason;
 835→        if (debugMode) {
 836→            return sendShareImageDebug(res, debugPayload);
 837→        }
 838→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 839→    };
 840→
 841→    try {
 842→        const journal = await getShareJournal(journalId);
 843→        debugPayload.stage = 'journal_loaded';
 844→        if (!journal) {
 845→            return fallbackWithReason('journal_not_found');
 846→        }
 847→
 848→        const shareMeta = buildShareMetaFromJournal(journal);
 849→        debugPayload.stage = 'candidate_extracted';
 850→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
 851→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
 852→
 853→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
 854→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
 855→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
 856→            return fallbackWithReason(candidateEvaluation.reason);
 857→        }
 858→
 859→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
 860→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
 861→            return fallbackWithReason('candidate_is_default_fallback');
 862→        }
 863→
 864→        debugPayload.stage = 'fetching_upstream';
 865→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
 866→        debugPayload.stage = 'upstream_loaded';
 867→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
 868→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
 869→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
 870→
 871→        debugPayload.stage = 'converting_image';
 872→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
 873→        debugPayload.stage = 'converted_image';
 874→        debugPayload.ok = true;
 875→        debugPayload.reason = 'ok';
 876→        debugPayload.meta.outputBytes = ogImageBuffer.length;
 877→
 878→        if (debugMode) {
 879→            return sendShareImageDebug(res, debugPayload);
 880→        }
 881→
 882→        res.set('Content-Type', 'image/jpeg');
 883→        res.set('Cache-Control', 'public, max-age=3600');
 884→        return res.send(ogImageBuffer);
 885→    } catch (err) {
 886→        debugPayload.stage = 'error';
 887→        debugPayload.reason = err?.message || 'unknown_error';
 888→        console.error('share image route error:', err?.message || err);
