 993→            bytesSent: stat.bytesSent,
 994→            statusBuckets: stat.statusBuckets,
 995→        }))
 996→        .sort((a, b) => b.count - a.count);
 997→
 998→    return {
 999→        startedAt: metricsState.startedAt,
1000→        requests: metricsState.requests,
1001→        responses: metricsState.responses,
1002→        inFlight: metricsState.inFlight,
1003→        bytesSent: metricsState.bytesSent,
