156→const loadUniversePostsFallback = async(minX, maxX, minY, maxY, limit) => {
157→    const settledQuery = supabase
158→        .from('journals')
159→        .select(UNIVERSE_POST_SELECT)
160→        .eq('privacy', 'public')
161→        .not('settled_x', 'is', null)
162→        .not('settled_y', 'is', null)
163→        .gte('settled_x', minX)
164→        .lte('settled_x', maxX)
165→        .gte('settled_y', minY)
166→        .lte('settled_y', maxY)
167→        .order('created_at', {ascending: false})
168→        .limit(limit);
169→
170→    const unsettledQuery = supabase
171→        .from('journals')
172→        .select(UNIVERSE_POST_SELECT)
173→        .eq('privacy', 'public')
174→        .is('settled_x', null)
175→        .is('settled_y', null)
176→        .gte('universe_x', minX)
177→        .lte('universe_x', maxX)
178→        .gte('universe_y', minY)
179→        .lte('universe_y', maxY)
180→        .order('created_at', {ascending: false})
181→        .limit(limit);
182→
183→    const [
184→        {data: settledData, error: settledError},
185→        {data: unsettledData, error: unsettledError}
186→    ] = await Promise.all([settledQuery, unsettledQuery]);
187→
188→    if(settledError || unsettledError){
189→        console.error(
190→            'supabase fallback error while fetching universe posts:',
191→            settledError?.message || unsettledError?.message
192→        );
193→        throw {status: 500, error: 'failed to fetch universe posts'};
194→    }
195→
196→    const mergedById = new Map();
197→    const mergedRows = [...(settledData || []), ...(unsettledData || [])];
198→    for (const row of mergedRows) {
