799→        const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
800→        const views = journal?.views || 0;
801→        const hotScore = (views * 6) + (likes * 3) + (comments * 2) + (bookmarks * 2);
802→
803→        return {
804→            ...journal,
805→            hot_score: hotScore
806→        };
807→    });
